const clusters = {
  'AI Education': ['education','training','learning','upskilling'],
  'Automation': ['automation','workflow','process','robotic'],
  'AI Ethics': ['ethics','bias','privacy','responsibility'],
  'AI Trends': ['trends','future','emerging','latest','breakthrough'],
  'Podcast Discovery': ['podcast','episode','listen','subscribe']
};

const text = $json["transcript"].toLowerCase();
let bestCluster = '';
let bestScore = 0;

for (const [cluster, keywords] of Object.entries(clusters)) {
  let score = 0;
  keywords.forEach(k => {
    const matches = text.match(new RegExp(`\\b${k}\\b`, 'g'));
    if (matches) score += matches.length;
  });
  if (score > bestScore) {
    bestScore = score;
    bestCluster = cluster;
  }
}

return [{ json: { primaryCluster: bestCluster || 'AI Trends', transcript: $json["transcript"] } }];
